import React, { useState, useEffect } from 'react';
import { MapPin, History, BrainCircuit, Navigation, Activity, Loader2, Clock, CheckCircle2, BarChart3 } from 'lucide-react';

function App() {
  const [history, setHistory] = useState("");
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState(null);
  const [error, setError] = useState(null);
  const [logs, setLogs] = useState([]);

  useEffect(() => {
    const savedLogs = localStorage.getItem('st_recent_logs');
    if (savedLogs) setLogs(JSON.parse(savedLogs));
  }, []);

  const handlePredict = async () => {
    if (!history) return;
    setLoading(true); setError(null);
    try {
      const historyArray = history.split(',').map(num => parseInt(num.trim()));
      const response = await fetch('http://localhost:8000/predict', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(historyArray)
      });
      const data = await response.json();
      setResult(data);
      const newLog = { id: Date.now(), input: history, prediction: data.recommendations[0].name, time: data.current_time };
      const updatedLogs = [newLog, ...logs].slice(0, 6);
      setLogs(updatedLogs);
      localStorage.setItem('st_recent_logs', JSON.stringify(updatedLogs));
    } catch (err) { setError(err.message); } finally { setLoading(false); }
  };

  return (
    <div className="min-h-screen bg-slate-50 flex">
      {/* Sidebar */}
      <div className="w-72 bg-slate-900 text-white p-6 hidden md:flex flex-col border-r border-slate-800">
        <div className="flex items-center gap-3 mb-10">
          <BrainCircuit className="text-blue-400" size={32} />
          <h1 className="font-bold text-xl tracking-tight">ST-HybridRec</h1>
        </div>
        <div className="flex-1 overflow-y-auto">
          <h3 className="text-xs font-bold text-slate-500 uppercase tracking-widest mb-4 flex items-center gap-2"><History size={14} /> Recent Activity</h3>
          <div className="space-y-3">
            {logs.map(log => (
              <div key={log.id} className="bg-slate-800/40 p-3 rounded-xl border border-slate-700/50">
                <div className="flex justify-between text-[10px] text-blue-400 font-bold"><span>Input: {log.input}</span><span>{log.time}</span></div>
                <p className="text-xs text-slate-300 truncate">➜ {log.prediction}</p>
              </div>
            ))}
          </div>
        </div>
      </div>

      {/* Main */}
      <main className="flex-1 p-8 overflow-y-auto">
        <header className="flex justify-between items-center mb-8">
          <div><h2 className="text-2xl font-bold text-slate-800">Spatial-Temporal Analysis</h2><p className="text-slate-500 text-sm">NYC Foursquare Deep Learning Fusion</p></div>
          <div className="text-xs font-mono bg-green-100 text-green-700 px-3 py-1 rounded-full border border-green-200 flex items-center gap-2">
            <div className="h-2 w-2 bg-green-500 rounded-full animate-pulse"></div> Engine: Online
          </div>
        </header>

        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
          <div className="lg:col-span-1 space-y-6">
            <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
              <label className="block text-sm font-semibold text-slate-700 mb-2">Visit History Trace</label>
              <input type="text" value={history} onChange={(e) => setHistory(e.target.value)} placeholder="e.g. 0, 1, 2" className="w-full px-4 py-3 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none transition-all"/>
              <button onClick={handlePredict} disabled={loading || !history} className="w-full mt-6 bg-blue-600 hover:bg-blue-700 text-white font-bold py-4 rounded-xl shadow-lg active:scale-95 disabled:bg-slate-300">
                {loading ? <Loader2 className="animate-spin m-auto" /> : "Run Hybrid Inference"}
              </button>
            </div>

            {/* PERFORMANCE METRICS CARD */}
            {result && result.metrics && (
              <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200 animate-in fade-in duration-500">
                <h3 className="text-xs font-bold text-slate-500 uppercase tracking-widest mb-4 flex items-center gap-2"><BarChart3 size={14} className="text-blue-500" /> Performance Matrix</h3>
                <div className="grid grid-cols-2 gap-3">
                  {[["Accuracy", result.metrics.accuracy], ["F1-Score", result.metrics.f1_score], ["Precision", result.metrics.precision], ["Recall", result.metrics.recall]].map(([label, val]) => (
                    <div key={label} className="p-3 bg-slate-50 rounded-xl border border-slate-100 text-center">
                      <p className="text-[9px] text-slate-400 font-bold uppercase">{label}</p>
                      <p className={`text-base font-black ${label === 'F1-Score' ? 'text-blue-600' : 'text-slate-700'}`}>{(val * 100).toFixed(1)}%</p>
                    </div>
                  ))}
                </div>
              </div>
            )}
          </div>

          <div className="lg:col-span-2 space-y-6">
            {result && (
              <div className="space-y-6 animate-in slide-in-from-bottom-5 duration-700">
                <div className="bg-white border-l-4 border-blue-500 rounded-r-2xl p-5 shadow-sm flex justify-between items-center">
                  <div><p className="text-[10px] font-bold text-blue-600 uppercase mb-1">Semantic Reasoning</p><div className="flex items-center gap-2 text-slate-700 font-semibold"><Clock size={16} />{result.reasoning}</div></div>
                  <div className="text-right"><p className="text-[10px] font-bold text-slate-400 uppercase mb-1">Traceability</p><code className="bg-slate-100 px-3 py-1 rounded-lg text-slate-600 font-bold text-xs">[{result.input_echo.join(", ")}]</code></div>
                </div>
                <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                  {result.recommendations.map((poi, i) => (
                    <div key={i} className={`relative bg-white border rounded-2xl p-6 hover:shadow-lg transition-all ${i === 0 ? 'border-blue-500' : 'border-slate-200'}`}>
                      <div className={`absolute top-0 right-0 px-3 py-1 rounded-bl-xl text-[9px] font-black ${i === 0 ? 'bg-blue-600 text-white' : 'bg-slate-100 text-slate-500'}`}>RANK #{i+1}</div>
                      <div className="mt-4"><span className="text-[10px] bg-slate-100 px-2 py-0.5 rounded-full font-bold uppercase text-slate-500">{poi.category}</span><h3 className="text-lg font-bold text-slate-800 mt-2 truncate">{poi.name}</h3></div>
                      <div className="mt-6"><div className="flex justify-between mb-2"><span className="text-[10px] text-slate-400 font-bold uppercase">Confidence</span><span className={`text-lg font-black ${i === 0 ? 'text-blue-600' : 'text-slate-600'}`}>{(poi.confidence * 100).toFixed(0)}%</span></div>
                      <div className="bg-slate-100 h-1.5 rounded-full overflow-hidden"><div className={`h-full transition-all duration-1000 ${i === 0 ? 'bg-blue-600' : 'bg-slate-400'}`} style={{ width: `${poi.confidence * 100}%` }}></div></div></div>
                    </div>
                  ))}
                </div>
              </div>
            )}
          </div>
        </div>
      </main>
    </div>
  );
}
export default App;
